## 四、操作插件脚本开发

### 4.1 操作插件模板

```javascript
operation {
    // 操作执行前校验
    beforeExecute(args) {
        var data = this.getModel().getDataEntity();

        // 校验逻辑
        if (data.amount <= 0) {
            this.addErrorMessage("金额必须大于0");
            return false;
        }

        return true;
    }

    // 操作执行中
    execute(args) {
        var data = this.getModel().getDataEntity();

        // 处理逻辑
        data.processTime = new Date();

        return true;
    }

    // 操作执行后
    afterExecute(result) {
        if (result.success) {
            this.getView().showSuccessNotification("操作成功");
        }
    }
}
```

