// 离线保存数据
saveOffline(data) {
    // 保存到本地
    this.localStore.save("order_" + data.id, data);

    // 标记待同步
    this.syncQueue.add({
        type: "order",
        id: data.id,
        action: "save",
        timestamp: new Date()
    });
}
