## 🔌 WebSocket连接

### 1. 连接地址

**连接URL**:
```
ws://hostname:port/ws
wss://hostname:port/ws  (SSL)
```

**认证方式**:
```javascript
// 方式1：URL参数
ws://hostname:port/ws?token=YOUR_TOKEN

// 方式2：消息认证
{
  "type": "auth",
  "token": "YOUR_TOKEN"
}
```

### 2. 连接管理

**JavaScript客户端**:
```javascript
class K3CloudWebSocket {
  constructor(url, options = {}) {
    this.url = url;
    this.options = {
      reconnectInterval: 5000,
      maxReconnectAttempts: 10,
      heartbeatInterval: 30000,
      ...options
    };

    this.ws = null;
    this.reconnectAttempts = 0;
    this.heartbeatTimer = null;
    this.subscriptions = new Map();
    this.eventHandlers = new Map();
  }

  // 连接
  connect() {
    return new Promise((resolve, reject) => {
      try {
        this.ws = new WebSocket(this.url);

        this.ws.onopen = () => {
          console.log('WebSocket connected');
          this.reconnectAttempts = 0;
          this.startHeartbeat();
          this.emit('connected');
          resolve();
        };

        this.ws.onmessage = (event) => {
          this.handleMessage(event.data);
        };

        this.ws.onerror = (error) => {
          console.error('WebSocket error:', error);
          this.emit('error', error);
          reject(error);
        };

        this.ws.onclose = () => {
          console.log('WebSocket disconnected');
          this.stopHeartbeat();
          this.emit('disconnected');
          this.handleReconnect();
        };

      } catch (error) {
        reject(error);
      }
    });
  }

  // 断开连接
  disconnect() {
    if (this.ws) {
      this.ws.close();
      this.ws = null;
    }
    this.stopHeartbeat();
  }

  // 处理重连
  handleReconnect() {
    if (this.reconnectAttempts < this.options.maxReconnectAttempts) {
      this.reconnectAttempts++;
      console.log(`Reconnecting... Attempt ${this.reconnectAttempts}`);

      setTimeout(() => {
        this.connect().catch(console.error);
      }, this.options.reconnectInterval);
    } else {
      console.error('Max reconnection attempts reached');
      this.emit('reconnect_failed');
    }
  }

  // 开始心跳
  startHeartbeat() {
    this.heartbeatTimer = setInterval(() => {
      this.send({ type: 'ping' });
    }, this.options.heartbeatInterval);
  }

  // 停止心跳
  stopHeartbeat() {
    if (this.heartbeatTimer) {
      clearInterval(this.heartbeatTimer);
      this.heartbeatTimer = null;
    }
  }

  // 发送消息
  send(data) {
    if (this.ws && this.ws.readyState === WebSocket.OPEN) {
      const message = typeof data === 'string' ? data : JSON.stringify(data);
      this.ws.send(message);
    }
  }

  // 处理消息
  handleMessage(data) {
    try {
      const message = JSON.parse(data);

      switch (message.type) {
        case 'pong':
          // 心跳响应
          break;

        case 'auth':
          this.handleAuthResponse(message);
          break;

        case 'subscribe':
          this.handleSubscribeResponse(message);
          break;

        case 'notification':
          this.handleNotification(message);
          break;

        case 'data':
          this.handleData(message);
          break;

        case 'error':
          this.handleError(message);
          break;

        default:
          console.warn('Unknown message type:', message.type);
      }

    } catch (error) {
      console.error('Parse message error:', error);
    }
  }

  // 认证
  authenticate(token) {
    this.send({
      type: 'auth',
      token: token
    });
  }

  // 处理认证响应
  handleAuthResponse(message) {
    if (message.success) {
      this.emit('authenticated');
    } else {
      this.emit('auth_failed', message.error);
    }
  }

  // 订阅
  subscribe(topic, callback) {
    const subscriptionId = this.generateId();

    this.subscriptions.set(subscriptionId, { topic, callback });

    this.send({
      type: 'subscribe',
      subscriptionId: subscriptionId,
      topic: topic
    });

    return subscriptionId;
  }

  // 取消订阅
  unsubscribe(subscriptionId) {
    if (this.subscriptions.has(subscriptionId)) {
      this.subscriptions.delete(subscriptionId);

      this.send({
        type: 'unsubscribe',
        subscriptionId: subscriptionId
      });
    }
  }

  // 处理订阅响应
  handleSubscribeResponse(message) {
    const { subscriptionId, success, error } = message;

    if (!success) {
      console.error('Subscribe failed:', error);
      this.subscriptions.delete(subscriptionId);
    }
  }

  // 处理数据
  handleData(message) {
    const { subscriptionId, data } = message;
    const subscription = this.subscriptions.get(subscriptionId);

    if (subscription && subscription.callback) {
      subscription.callback(data);
    }
  }

  // 处理通知
  handleNotification(message) {
    this.emit('notification', message.data);
  }

  // 处理错误
  handleError(message) {
    console.error('Server error:', message.error);
    this.emit('error', message.error);
  }

  // 事件监听
  on(event, handler) {
    if (!this.eventHandlers.has(event)) {
      this.eventHandlers.set(event, []);
    }
    this.eventHandlers.get(event).push(handler);
  }

  // 移除事件监听
  off(event, handler) {
    if (this.eventHandlers.has(event)) {
      const handlers = this.eventHandlers.get(event);
      const index = handlers.indexOf(handler);
      if (index > -1) {
        handlers.splice(index, 1);
      }
    }
  }

  // 触发事件
  emit(event, data) {
    if (this.eventHandlers.has(event)) {
      this.eventHandlers.get(event).forEach(handler => {
        handler(data);
      });
    }
  }

  // 生成ID
  generateId() {
    return Math.random().toString(36).substr(2, 9);
  }
}

// 使用示例
const ws = new K3CloudWebSocket('wss://k3cloud.example.com/ws');

ws.on('connected', () => {
  console.log('Connected to server');
  ws.authenticate('YOUR_TOKEN');
});

ws.on('authenticated', () => {
  console.log('Authenticated successfully');

  // 订阅单据状态变更
  const subscriptionId = ws.subscribe('bill.status.changed', (data) => {
    console.log('Bill status changed:', data);
  });

  // 订阅消息通知
  ws.subscribe('notification', (notification) => {
    console.log('New notification:', notification);
  });
});

ws.on('notification', (notification) => {
  // 显示通知
  showNotification(notification);
});

ws.connect().catch(console.error);
```

