const OUTPUT_DIR = '/root/.openclaw/knowledge-base/金蝶云苍穹/专题文档/文档内容';
const BASE_URL = 'https://vip.kingdee.com/knowledge/';

async function extractDocument(page) {
  return await page.evaluate(() => {
    // 提取文档内容
    const titleEl = document.querySelector('h1, .doc-title, .knowledge-title');
    const title = titleEl ? titleEl.textContent.trim() : '';

    const contentEl = document.querySelector('.doc-content, .knowledge-content, article, .markdown-body');
    const content = contentEl ? contentEl.innerText : '';

    return { title, content };
  });
}

async function main() {
  console.log('启动浏览器...');
  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });

  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
  });

  const page = await context.newPage();

  let successCount = 0;
  let failCount = 0;

  for (let i = 0; i < DOC_IDS.length; i++) {
    const docId = DOC_IDS[i];
    const url = BASE_URL + docId;

    console.log(`[${i + 1}/${DOC_IDS.length}] 抓取: ${url}`);

    try {
      await page.goto(url, { waitUntil: 'networkidle', timeout: 30000 });
      await page.waitForTimeout(2000);

      const { title, content } = await extractDocument(page);

      if (content && content.length > 100) {
        const filename = `${docId}_${title.replace(/[\/\\:*?"<>|]/g, '_').substring(0, 50)}.md`;
        const filepath = path.join(OUTPUT_DIR, filename);

        const mdContent = `# ${title}\n\n> 文档ID: ${docId}\n> URL: ${url}\n> 提取时间: ${new Date().toISOString().split('T')[0]}\n\n---\n\n${content}`;

        fs.writeFileSync(filepath, mdContent, 'utf8');
        console.log(`  ✅ 成功: ${title} (${content.length}字)`);
        successCount++;
      } else {
        console.log(`  ⚠️ 内容为空或过短`);
        failCount++;
      }

      // 避免请求过快
      await page.waitForTimeout(1500);

    } catch (error) {
      console.log(`  ❌ 失败: ${error.message}`);
      failCount++;
    }
  }

  await browser.close();

  console.log(`\n========== 抓取完成 ==========`);
  console.log(`成功: ${successCount}`);
  console.log(`失败: ${failCount}`);
}

main().catch(console.error);

