];

const OUTPUT_DIR = '/root/.openclaw/knowledge-base/金蝶云苍穹/专题文档/文档内容';
const BASE_URL = 'https://vip.kingdee.com/knowledge/';

async function fetchWithRetry(url, retries = 3) {
  for (let i = 0; i < retries; i++) {
    try {
      const response = await fetch(url, {
        headers: {
          'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
          'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
        }
      });
      return response;
    } catch (error) {
      if (i === retries - 1) throw error;
      await new Promise(r => setTimeout(r, 2000));
    }
  }
}

async function main() {
  console.log('开始批量抓取文档...');
  console.log(`待抓取文档数: ${DOC_IDS.length}`);

  let successCount = 0;
  let failCount = 0;

  for (let i = 0; i < DOC_IDS.length; i++) {
    const docId = DOC_IDS[i];
    const url = BASE_URL + docId + '?productLineId=29&isKnowledge=2&lang=zh-CN';

    console.log(`\n[${i + 1}/${DOC_IDS.length}] 抓取: ${url}`);

    try {
      const response = await fetchWithRetry(url);
      const html = await response.text();

      // 提取标题
      const titleMatch = html.match(/<h1[^>]*>([^<]+)<\/h1>/);
      const title = titleMatch ? titleMatch[1].trim() : `文档${docId}`;

      // 提取内容 - 查找文档正文区域
      const contentMatch = html.match(/<div[^>]*class="[^"]*doc-content[^"]*"[^>]*>([\s\S]*?)<\/div>\s*<\/div>\s*<\/div>/i) ||
                          html.match(/<article[^>]*>([\s\S]*?)<\/article>/i) ||
                          html.match(/<div[^>]*class="[^"]*markdown-body[^"]*"[^>]*>([\s\S]*?)<\/div>/i);

      if (contentMatch) {
        let content = contentMatch[1];

        // 简单清理HTML标签
        content = content
          .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
          .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
          .replace(/<[^>]+>/g, ' ')
          .replace(/\s+/g, ' ')
          .trim();

        if (content.length > 200) {
          const safeTitle = title.replace(/[\/\\:*?"<>|]/g, '_').substring(0, 50);
          const filename = `${docId}_${safeTitle}.md`;
          const filepath = path.join(OUTPUT_DIR, filename);

          const mdContent = `# ${title}\n\n> 文档ID: ${docId}\n> URL: ${url}\n> 提取时间: ${new Date().toISOString().split('T')[0]}\n\n---\n\n${content}`;

          fs.writeFileSync(filepath, mdContent, 'utf8');
          console.log(`  ✅ 成功: ${title} (${content.length}字)`);
          successCount++;
        } else {
          console.log(`  ⚠️ 内容过短 (${content.length}字)`);
          failCount++;
        }
      } else {
        console.log(`  ❌ 未找到内容区域`);
        failCount++;
      }

      // 延迟避免请求过快
      await new Promise(r => setTimeout(r, 1500));

    } catch (error) {
      console.log(`  ❌ 失败: ${error.message}`);
      failCount++;
    }
  }

  console.log(`\n========== 抓取完成 ==========`);
  console.log(`成功: ${successCount}`);
  console.log(`失败: ${failCount}`);
}

main().catch(console.error);

