  // 获取URL中的文档ID
  const urlParams = new URLSearchParams(window.location.search);
  const docId = urlParams.get('id') || '';

  return {
    title: title || '文档',
    content: mainContent.substring(0, 20000),
    url: window.location.href,
    docId
  };
}

